export const getGetAnalyticsTimeSeriesUrl = (params?: GetAnalyticsTimeSeriesParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/analytics/time-series?${stringifiedParams}` : `/api/analytics/time-series`
}

